CREATE TABLE srup_arvores_point (
	fid int8 NOT NULL,
	designacao text NULL,
	servidao text NULL,
	tipologia text NULL,
	lei_tipo text NULL,
	serv_dr text NULL,
	serv_data timestamptz NULL,
	serv_hiper text NULL,
	serv_lei text NULL,
	municipios text NULL,
	geom public.geometry(multipoint, 3763) NULL,
	CONSTRAINT srup_arvores_point_pk PRIMARY KEY (fid)
);
CREATE INDEX idx_srup_arvores_point_geom ON srup_arvores_point USING gist (geom);

